// Parser la sortie de itsm-sync.py --backend servicenow
const stdout = $input.item.json.stdout || '';
const exitCode = $input.item.json.exitCode ?? 0;

// Extraire le vrai code de sortie
let realExit = exitCode;
const exitMatch = stdout.match(/EXIT:(\d+)/);
if (exitMatch) realExit = parseInt(exitMatch[1]);

// Extraire les numéros INC créés : 'CREE [servicenow] T_xxx → INC0012345'
const incMatches = [...stdout.matchAll(/INC\d+/g)];
const incNumbers = [...new Set(incMatches.map(m => m[0]))];

// Extraire le nombre de tickets créés depuis le résumé
const createdMatch = stdout.match(/Créés\s*:\s*(\d+)/);
const failedMatch  = stdout.match(/Echecs\s*:\s*(\d+)/);
const skippedMatch = stdout.match(/Skippés\s*:\s*(\d+)/);

const createdCount = createdMatch ? parseInt(createdMatch[1]) : incNumbers.length;
const failedCount  = failedMatch  ? parseInt(failedMatch[1])  : 0;
const skippedCount = skippedMatch ? parseInt(skippedMatch[1]) : 0;

console.log(`[snow-sync] exit=${realExit} | créés=${createdCount} | echecs=${failedCount} | skippés=${skippedCount}`);
console.log(`[snow-sync] INC créés: ${incNumbers.join(', ') || 'aucun'}`);

return [{
  json: {
    stdout,
    exitCode: realExit,
    createdCount,
    failedCount,
    skippedCount,
    incNumbers,
    hasCreated: createdCount > 0,
    timestamp: new Date().toISOString()
  }
}];

// Construire la carte Teams pour ServiceNow
const {
  createdCount, failedCount, skippedCount, incNumbers, timestamp
} = $input.item.json;

const dateStr = new Date(timestamp).toLocaleString('fr-FR', {
  timeZone: 'Europe/Paris',
  dateStyle: 'short',
  timeStyle: 'short'
});

// Liste des INC créés (max 10)
const incList = incNumbers.slice(0, 10).join(', ');
const incMore = incNumbers.length > 10 ? ` (+${incNumbers.length - 10} autres)` : '';

const payload = {
  type: 'message',
  attachments: [{
    contentType: 'application/vnd.microsoft.card.adaptive',
    content: {
      '$schema': 'http://adaptivecards.io/schemas/adaptive-card.json',
      type: 'AdaptiveCard',
      version: '1.4',
      body: [
        {
          type: 'TextBlock',
          text: `NetWatch → ServiceNow — ${dateStr}`,
          weight: 'Bolder',
          size: 'Large',
          color: 'Accent',
          wrap: true
        },
        {
          type: 'TextBlock',
          text: `${createdCount} incident(s) créé(s) dans ServiceNow`,
          size: 'Medium',
          wrap: true
        },
        {
          type: 'FactSet',
          facts: [
            { title: 'Créés',    value: String(createdCount) },
            { title: 'Echecs',   value: String(failedCount) },
            { title: 'Skippés', value: String(skippedCount) },
            { title: 'INC',      value: incList + incMore || 'N/A' }
          ]
        }
      ],
      actions: [{
        type: 'Action.OpenUrl',
        title: 'Ouvrir NetWatch',
        url: 'http://localhost:5050'
      }]
    }
  }]
};

return [{ json: payload }];
